    );
    const provider = createWorkspaceDeployProvider('cloudflare_workers_assets', {
      CF_ACCOUNT_ID: 'acc',
      CF_API_TOKEN: 'token',
      WORKSPACE_DEPLOY_PREVIEW_DOMAIN: 'preview.example.com',
